var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"진심이신가요, 사장님?","JPN":"本気ですか、社長？","ENG":"You mean it, Boss?","TWN":"您是認真的嗎，老闆？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잠시 머물다 떠날 파견학생에게 눈 하나 깜짝 않고 이런 제안을 해오시다니 참 짓궂으시네요.","JPN":"しばらく滞在するだけの派遣の学生に、あっさりとこんな提案をするなんて、本当に意地悪な方ですね。","ENG":"It's mighty naughty of you to make such an offer without so much as batting an eye to an exchange student who is soon due to leave.","TWN":"您居然會毫不猶疑地對短暫停留的派遣學生提出這種提議，您真的好壞啊。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 물론 이 제안을 승낙할 겁니다.","JPN":"もちろん、私はこの提案を引き受けます。","ENG":"Of course, I do accept the offer.","TWN":"我當然會接受這個提議。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제가 존경하는 분의 곁에서 배움을 겸하며 일할 수 있다면 마다할 이유가 없죠.","JPN":"私が尊敬する方のそばで勉強と仕事ができるなら、断る理由はありません。","ENG":"I have no reason to turn down the opportunity to learn and work by someone I respect so dearly.","TWN":"能在我尊敬的人身邊工作順便學習，我沒有拒絕的理由吧。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"사장님 같은 분에겐 학생으로서도, 한 집단을 이끄는 리더로서도 배울 점이 많다고 생각하거든요.","JPN":"社長のような方には、学生としても、一つの集団を率いるリーダーとしても、学べることがたくさんあると思います。","ENG":"I have much to learn from you as a student and as a leader.","TWN":"因為像老闆您這樣的人，不管是作為學生還是帶領一個組織的領導者，都有很多值得我學習的地方。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후훗, 본인은 무슨 말인지 전혀 모르겠다는 표정이시네요. 마치 평소의 그 새침데기 로봇처럼.","JPN":"ふふっ、本人は何を言ってるのかまったくわからないという表情ですね。まるで普段のあのすましたロボットみたいに。","ENG":"Hah hah, you seem puzzled by my assessment of your qualities. Like that clueless robot face of yours...","TWN":"呵呵，您怎麼一副不懂這是什麼意思的表情啊，就跟平時那個愛裝模作樣的機器人似的。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제겐 사장님의 진중한 마음가짐이 느껴져요.","JPN":"社長の真剣な志が感じられるんですよ。","ENG":"But I can tell there's a certain gravity to you that betrays your carefree mien.","TWN":"我能感受到老闆對這件事慎重的心情。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"겉으론 가볍고 대수롭지 않은 척하지만, 본질은 속 깊고 인정이 많은 분이라는 걸 저는 느낄 수 있어요.","JPN":"社長は軽い人と思われがちですが、本当は気配り上手で情け深い方であることを私は知っています。","ENG":"While you are ostensibly light-hearted, I can tell deep within you are very caring and affectionate.","TWN":"我知道，您表面上雖然裝作若無其事的樣子，但實際上卻是一個心思細膩、充滿人情味的人。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"전 오히려 사장님과 반대로 모두와 허물없이 지내고 싶지만, 평소의 태도가 너무 진지하다는 지적을 받곤 하거든요.","JPN":"私は社長と真逆なタイプで、みんなと気をゆるして過ごしたいんですが、普段の態度が真面目すぎると指摘されたりします。","ENG":"As for me, I really want to be friends with everyone, but they all tell me that I'm too serious all the time.","TWN":"和老闆正好相反，雖然我想跟大家輕鬆自在地相處，但卻經常有人說我平時的態度太認真了。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇기 때문에 저는 사장님에게 어울리는 파트너가 될 거란 확신이 들었어요.","JPN":"だからこそ、私は社長にふさわしいパートナーになれると確信しました。","ENG":"That led me to believe that I'd make the ideal partner for you.","TWN":"因此，我才確信自己能成為配得上老闆的夥伴。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 학생들과 소통하는 학생회장의 입장에서, 소통의 분위기를 조성하는 일은 정말 중요하거든요.","JPN":"アカデミーの生徒たちとコミュニケーションを取る生徒会長として、話しやすい雰囲気を作ることはとても大事なことです。","ENG":"As the Student President of the Academy, I bear the important task of setting the mood for open and transparent communication.","TWN":"作為與學院學生溝通的學生會會長，營造良好的溝通氣氛是非常重要的。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 그건, 비단 저만의 문제가 아닌 사장님과 직원들 사이에서도 해당되는 문제겠죠.","JPN":"そしてそれは、私だけの問題じゃなく社長と社員の関係にも当てはまることだと思います。","ENG":"I suppose that task falls not only to myself, but also to you and all the employees here.","TWN":"然後，這不僅僅是我的問題，老闆與員工之間也一樣。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"날 따라주는 이들에게 온전한 진심을 다 전하고자......","JPN":"私についてきてくれる者たちに真心を伝えるために……","ENG":"If I am to truly open myself up to everyone under my leadership... ","TWN":"為了對追隨自己的人如實地傳達真心……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};